'use client';

import { useEffect, useMemo, useState } from 'react';
import { Button } from './ui/button';
import { Skeleton } from './ui/skeleton';
import { SignViewer } from './sign-viewer';

export function GestureSequencePlayer({
  gestures,
  loading,
}: {
  gestures: string[];
  loading?: boolean;
}) {
  const [index, setIndex] = useState(0);
  const [playing, setPlaying] = useState(false);

  const current = useMemo(() => gestures[index] ?? null, [gestures, index]);

  // Debug logging for gestures
  useEffect(() => {
    console.log('[GestureSequencePlayer] gestures:', gestures);
    if (gestures.length > 0) {
      console.log('[GestureSequencePlayer] first gesture (first 100 chars):', gestures[0].substring(0, 100));
      console.log('[GestureSequencePlayer] first gesture length:', gestures[0].length);
    }
  }, [gestures]);

  useEffect(() => {
    setIndex(0);
    setPlaying(false);
  }, [gestures.join('|')]);

  useEffect(() => {
    if (!playing) return;
    if (gestures.length <= 1) return;

    const t = window.setInterval(() => {
      setIndex((i) => (i + 1) % gestures.length);
    }, 700);

    return () => window.clearInterval(t);
  }, [playing, gestures.length]);

  if (loading) {
    return (
      <div className="mt-2">
        <Skeleton className="h-[360px] w-full" />
      </div>
    );
  }

  return (
    <div className="mt-2 space-y-3">
      <div className="grid place-items-center rounded-xl border border-slate-800 bg-slate-950 p-3">
        {current ? <SignViewer url={current} /> : <div className="py-16 text-sm text-slate-500">No output</div>}
      </div>
      <div className="flex gap-2">
        <Button
          variant="secondary"
          onClick={() => setIndex((i) => Math.max(0, i - 1))}
          disabled={!gestures.length || index === 0}
        >
          Prev
        </Button>
        <Button
          onClick={() => setPlaying((p) => !p)}
          disabled={gestures.length <= 1}
        >
          {playing ? 'Pause' : 'Play'}
        </Button>
        <Button
          variant="secondary"
          onClick={() => setIndex((i) => Math.min(gestures.length - 1, i + 1))}
          disabled={!gestures.length || index >= gestures.length - 1}
        >
          Next
        </Button>
        <div className="ml-auto text-xs text-slate-400 self-center">
          {gestures.length ? `${index + 1}/${gestures.length}` : ''}
        </div>
      </div>
    </div>
  );
}
